// Função para calcular MVA ajustado
function calcMvaAjustado(mvaOriginal: number, aliqInter: number, aliqInterna: number): number {
  const mvaDecimal = mvaOriginal / 100;
  const ajustado = ((1 + mvaDecimal) * (1 - aliqInter / 100) / (1 - aliqInterna / 100) - 1) * 100;
  return Math.round(ajustado * 100) / 100;
}

